def priority(el: tuple, n: int, w: int) -> float:
    # Inverse of maximum consecutive zero-run (avoid long runs)
    max_zero_run = 0
    current_run = 0
    for x in el:
        if x == 0:
            current_run += 1
            max_zero_run = max(max_zero_run, current_run)
        else:
            current_run = 0
    inv_max_run = 1.0 / (max_zero_run + 1)

    # Count triple-zero patterns (three consecutive zeros)
    triple_zeros = 0
    for i in range(n - 2):
        if el[i] == 0 and el[i+1] == 0 and el[i+2] == 0:
            triple_zeros += 1
    penalty_triple = triple_zeros * 2.0

    # Variance of non-zero positions (penalize uneven spacing)
    positions = [i for i, x in enumerate(el) if x != 0]
    if len(positions) >= 2:
        mean_pos = sum(positions) / len(positions)
        variance = sum((p - mean_pos) ** 2 for p in positions) / len(positions)
    else:
        variance = 0.0

    return inv_max_run * 10.0 - penalty_triple - variance * 0.3
